parameters.new_string:
/**
 * Send a notification through all registered adapters.
 * Notifications are queued and processed sequentially (FIFO) to guarantee
 * delivery ordering — e.g., "order placed" always arrives before "payment confirmed".
 * Each adapter attempts delivery independently — one failure does not block others.
 * Checks user preferences per-channel before sending — if the user has opted out
 * of a specific channel, that channel is skipped while others proceed.
 */
async send(payload: NotificationPayload): Promise<Notification[]> {
  const resultPromise = new Promise<Notification[]>((resolve) => {
    this.sendQueue = this.sendQueue.then(async () => {
      const results = await this.processSend(payload);
      resolve(results);
    });
  });
  return resultPromise;
}

private async processSend(payload: NotificationPayload): Promise<Notification[]> {
  this.logger.info(`Sending ${payload.type} notification to ${payload.recipient}`);

  const userId = payload.metadata?.userId as string | undefined;

  if (this.adapters.size === 0) {
    this.logger.warn('No adapters registered — notification will only be recorded in-memory');
  }

  const results: Notification[] = [];

  for (const adapter of this.adapters.values()) {
    // Check per-channel preferences if a preferences service is configured
    if (userId && this.preferencesService) {
      if (!this.preferencesService.shouldSendChannel(userId, payload.type, adapter.channel)) {
        this.logger.info(
          `Notification ${payload.type} suppressed for user ${userId} on channel ${adapter.channel} (preferences)`,
        );
        continue;
      }
    }

    const result = await adapter.send(payload);
    const record: Notification = {
      id: generateNotificationId(),
      type: payload.type,
      channel: adapter.channel,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      sentAt: new Date(),
      success: result.success,
      error: result.error,
    };
    this.notifications.push(record);
    this.historyService?.log(record);
    results.push(record);
  }

  // If no adapters, still record for in-memory tracking
  if (this.adapters.size === 0) {
    const record: Notification = {
      id: generateNotificationId(),
      type: payload.type,
      channel: 'in_app',
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      sentAt: new Date(),
      success: true,
    };
    this.notifications.push(record);
    this.historyService?.log(record);
    results.push(record);
  }

  return results;
}

